def json_error(message: str, status: int = 400):
    return jsonify({"error": message}), status


def normalize_url(url: str) -> str:
    url = (url or "").strip()
    if not url:
        raise ValueError("Missing URL")
    if not re.match(r"^[a-zA-Z][a-zA-Z0-9+\-.]*://", url):
        url = "https://" + url
    parsed = urlparse(url)
    if parsed.scheme not in ALLOWED_SCHEMES:
        raise ValueError("Only http and https URLs are allowed")
    if not parsed.netloc:
        raise ValueError("Invalid URL")
    host = parsed.hostname or ""
    if host.lower() in PRIVATE_HOSTS:
        raise ValueError("Private or localhost URLs are not allowed")
    if re.match(r"^(10\.|127\.|169\.254\.|172\.(1[6-9]|2\d|3[0-1])\.|192\.168\.)", host):
        raise ValueError("Private IP URLs are not allowed")
    return url


def make_key(url: str) -> str:
    digest = hashlib.sha256(url.encode("utf-8")).hexdigest()
    return f"{S3_PREFIX.rstrip('/')}/{digest[:2]}/{digest}.jpg"


def get_public_url(key: str) -> str:
    if BASE_PUBLIC_URL:
        return f"{BASE_PUBLIC_URL.rstrip('/')}/{key}"
    try:
        return s3.generate_presigned_url(
            "get_object",
            Params={"Bucket": S3_BUCKET, "Key": key},
            ExpiresIn=PRESIGNED_URL_EXPIRES,
        )
    except Exception:
        return f"https://{S3_BUCKET}.s3.{AWS_REGION}.amazonaws.com/{key}"


def s3_exists(bucket: str, key: str) -> bool:
    try:
        s3.head_object(Bucket=bucket, Key=key)
        return True
    except botocore.exceptions.ClientError as e:
        code = e.response.get("Error", {}).get("Code")
        if code in ("404", "NoSuchKey", "NotFound"):
            return False
        raise


def upload_bytes_to_s3(data: bytes, bucket: str, key: str, content_type: str = "image/jpeg", metadata: Optional[Dict[str, str]] = None):
    extra = {
        "ContentType": content_type,
        "ACL": "public-read" if not BASE_PUBLIC_URL else "private",
        "CacheControl": "public, max-age=31536000",
    }
    if metadata:
        extra["Metadata"] = metadata
    s3.put_object(Bucket=bucket, Key=key, Body=data, **extra)


def build_driver() -> webdriver.Chrome:
    options = Options()
    options.binary_location = CHROME_BINARY
    options.add_argument("--headless=new")
    options.add_argument("--disable-gpu")
    options.add_argument("--disable-dev-shm-usage")
    options.add_argument("--no-sandbox")
    options.add_argument("--hide-scrollbars")
    options.add_argument("--window-size=%d,%d" % (SCREENSHOT_WIDTH, SCREENSHOT_HEIGHT))
    options.add_argument("--disable-blink-features=AutomationControlled")
    options.add_argument("--disable-background-networking")
    options.add_argument("--disable-sync")
    options.add_argument("--metrics-recording-only")
    options.add_argument("--mute-audio")
    options.add_argument("--no-first-run")
    options.add_argument("--safebrowsing-disable-auto-update")
    options.page_load_strategy = "normal"
    service = webdriver.ChromeService(executable_path=CHROMEDRIVER_PATH)
    driver = webdriver.Chrome(service=service, options=options)
    driver.set_page_load_timeout(PAGE_LOAD_TIMEOUT)
    return driver


def render_page_to_png(url: str) -> bytes:
    driver = build_driver()
    try:
        driver.get(url)
        time.sleep(RENDER_WAIT_SECONDS)
        try:
            height = driver.execute_script("""
                return Math.max(
                    document.body ? document.body.scrollHeight : 0,
                    document.documentElement ? document.documentElement.scrollHeight : 0,
                    document.body ? document.body.offsetHeight : 0,
                    document.documentElement ? document.documentElement.offsetHeight : 0,
                    document.body ? document.body.clientHeight : 0,
                    document.documentElement ? document.documentElement.clientHeight : 0
                );
            """)
            height = max(int(height or SCREENSHOT_HEIGHT), SCREENSHOT_HEIGHT)
            height = min(height, 4000)
            driver.set_window_size(SCREENSHOT_WIDTH, height)
            time.sleep(0.5)
        except Exception:
            pass
        return driver.get_screenshot_as_png()
    finally:
        driver.quit()


def make_thumbnail(image_bytes: bytes, width: int = THUMBNAIL_WIDTH, height: int = THUMBNAIL_HEIGHT, quality: int = 85) -> bytes:
    with Image.open(io.BytesIO(image_bytes)) as img:
        img = img.convert("RGB")
        src_w, src_h = img.size
        src_ratio = src_w / src_h
        dst_ratio = width / height

        if src_ratio > dst_ratio:
            new_h = height
            new_w = int(height * src_ratio)
        else:
            new_w = width
            new_h = int(width / src_ratio)

        resized = img.resize((new_w, new_h), Image.LANCZOS)
        left = max((new_w - width) // 2, 0)
        top = max((new_h - height) // 2, 0)
        cropped = resized.crop((left, top, left + width, top + height))

        out = io.BytesIO()
        cropped.save(out, format="JPEG", quality=quality, optimize=True, progressive=True)
        return out.getvalue()


def validate_bucket():
    if not S3_BUCKET:
        raise RuntimeError("S3_BUCKET environment variable is required")


def screenshot_url(url: str, force: bool = False) -> Dict[str, Any]:
    validate_bucket()
    normalized = normalize_url(url)
    key = make_key(normalized)

    if not force and s3_exists(S3_BUCKET, key):
        return {
            "url": normalized,
            "s3_key": key,
            "image_url": get_public_url(key),
            "cached": True,
        }

    png_bytes = render_page_to_png(normalized)
    thumb_bytes = make_thumbnail(png_bytes)

    upload_bytes_to_s3(
        thumb_bytes,
        S3_BUCKET,
        key,
        content_type="image/jpeg",
        metadata={"source-url-hash": hashlib.sha256(normalized.encode("utf-8")).hexdigest()},
    )

    return {
        "url": normalized,
        "s3_key": key,
        "image_url": get_public_url(key),
        "cached": False,
    }


